VALUES
  ('social-worker-moex-01031', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '孕婦用藥安全級數都會被標示在藥品的包裝盒上，其中美國食品藥物管理局（FDA）將懷孕用藥 分為ABCDX等五級，其中X級代表的用藥安全級數是：', '["已證明對胎兒無危險", "對胎兒安全性尚未確立", "對胎兒有明確的危險性", "已證實會導致畸型，孕婦禁用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01032', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '人類行為與社會環境之重要概念也包含增權、優勢及復原力，其中在思考家庭的優勢（strengths） 時，不包含下列何者？', '["你可以從你的原生家庭中取得多少協助", "你如何向你的家人求助", "你的家庭最好的特質是什麼", "你的家庭具有那些衝突能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01033', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Piaget針對認知發展分為四個階段，下列敘述何者錯誤？', '["感覺動作期約為出生到2歲，其中要發展物體不滅，雖然東西不在視覺或聽覺範圍內，但永恆 存在", "前運思期開始會運用語言做更抽象的思考，有三個邏輯思考的阻礙，自我中心／專注／不可逆", "具體運思期約為小學階段，仍舊非常自我中心，而無法從他人角度思考，直到形式運思期", "形式運思期的兒童及少年，開始可以從別人的角度思考多元觀點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01034', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青少年發展階段中很重要的部分是同儕壓力跟從眾，下列敘述何者正確？', '["青少年可能需要友伴的認同，所以選擇類似的裝扮，參加相同的社團活動", "通常女性受到友伴團體的影響較男性大", "青少年跟同儕在一起，比較沒有冒險的行為與思考", "因為同儕壓力，少年會喜歡性霸凌同學"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01035', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '一個長期被霸凌的小孩，會轉向欺負其他比自己更弱小的對象，是那一種現象？', '["世代轉移", "社會從眾", "反擊性霸凌", "個人神話"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01036', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '相信自己是獨特的，全能而不必擔心被危險攻擊，這是因為他們相信自己是無懈可擊的／全能的； 這是DavidElkind（2006）對那一個發展階段的敘述？', '["學齡前期", "嬰兒期", "青少年期", "成年期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01037', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Freud將人格結構分為本我（id）、自我（ego）和超我（superego），下列敘述何者正確？', '["本我是受唯樂原則支配，行為動機單純在追求生物性需求與避免痛苦", "自我是唯樂主義又充分依附主要照顧者的階段", "自我是現實原則，一方面管制超我的原始衝動，又可以協助本我需求的滿足", "超我是壓抑原則的我，將道德規則建立起來，是人在嬰兒期就有的原始我"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01038', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那項觀點主張個體在老年時傾向於繼續維持一致的行為模式，來代替失去的社會角色，個體 將會尋找相似的角色以因應社會環境的變化，以維持原有的適應？', '["活動理論", "撤退理論", "社會繼續理論", "成功老化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01039', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '人從出生到死亡都被期待在固定時間完成生命的任務，例如：一個女孩在 30 歲左右應該要開始 準備結婚，所以家人會積極安排相親。係指下列何者？', '["社會任務", "社會標籤", "社會時鐘", "社會排除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01040', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關父母採用威權施壓管教方式的敘述，下列何者正確？', '["當父母採用威權施壓的管教方式容易讓兒少產生羞愧感", "當父母採用威權施壓的管教方式有助於自我控制的學習", "當父母採用威權施壓的管教方式會讓兒少覺得父母對他不理睬", "當父母採用威權施壓的管教方式會使兒少有機會表達自己的想法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
